import{_ as a,o as s,c as t,a2 as r}from"./chunks/framework.N9BN-Nr4.js";const p=JSON.parse('{"title":"Assassin","description":"","frontmatter":{},"headers":[],"relativePath":"formats/assassin/index.md","filePath":"formats/assassin/index.md","lastUpdated":1782025909000}'),i={name:"formats/assassin/index.md"};function n(o,e,l,c,d,h){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="assassin" tabindex="-1">Assassin <a class="header-anchor" href="#assassin" aria-label="Permalink to &quot;Assassin&quot;">​</a></h1><p>Assassin formats give each player a secret target, mark, or quarry. The game is still multiplayer, but players are not simply trying to kill everyone at once; the target map creates constrained attacks, temporary incentives, and sudden shifts when a target dies.</p><p>This is separate from BANG-like hidden-role formats. BANG-like games assign team or solo victory roles; Assassin-style games assign a player-to-player target.</p><h2 id="core-pattern" tabindex="-1">Core Pattern <a class="header-anchor" href="#core-pattern" aria-label="Permalink to &quot;Core Pattern&quot;">​</a></h2><ul><li>Each player receives a secret target.</li><li>Players are restricted, rewarded, or otherwise incentivized to pursue their target.</li><li>When a target dies, their mark may pass to the killer or otherwise change the target map.</li><li>The game usually ends when one player remains, or when a player reaches a required number of kills.</li></ul><h2 id="local-variants" tabindex="-1">Local Variants <a class="header-anchor" href="#local-variants" aria-label="Permalink to &quot;Local Variants&quot;">​</a></h2><ul><li><a href="./variants/hitmen.html">Hitmen</a>: A local Pegasus Loft mark/target variant with constrained attacking and targeting.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>Add more source notes for the broader Assassin format when you have them.</li><li>Decide whether Assassin gets <code>sources/</code> later if you find or copy external reference material.</li></ul>',9)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
